import Foundation

struct CategoryContent13 {
    static let aiTools = CategoryData(
        id: "ai_tools", name: "Cool AI Tools", icon: "wrench.and.screwdriver", colorName: "aiGreen",
        description: "The apps and tools powered by AI today",
        lessons: [lesson1, lesson2, lesson3, lesson4, lesson5, lesson6], order: 12,
        unlockRequirement: .completeCategoryMinimum("ai_basics")
    )

    static let lesson1 = LessonData(id: "at_l1", title: "The Big Models", description: "Meet the major AI language models", categoryId: "ai_tools", questions: [
        Question(id: "at1_q1", type: .multipleChoice, questionText: "Which company created the Claude family of AI models?", options: ["Anthropic", "OpenAI", "Google DeepMind", "Meta AI"], correctAnswer: "Anthropic", explanation: "Anthropic, founded by former OpenAI researchers Dario and Daniela Amodei, created Claude with a focus on AI safety and helpfulness."),
        Question(id: "at1_q2", type: .matchPairs, questionText: "Match each AI model to the company that created it:", matchPairs: [
            MatchPair(term: "GPT", definition: "OpenAI"),
            MatchPair(term: "Claude", definition: "Anthropic"),
            MatchPair(term: "Gemini", definition: "Google DeepMind"),
            MatchPair(term: "Llama", definition: "Meta AI")
        ], explanation: "Each major tech company and AI lab has developed its own flagship large language model, creating a competitive and rapidly evolving landscape."),
        Question(id: "at1_q3", type: .trueFalse, questionText: "Meta's Llama models are open-weight, meaning anyone can download and run them.", options: ["True", "False"], correctAnswer: "True", explanation: "Meta released the Llama model weights publicly, allowing researchers, developers, and companies to download, modify, and deploy them, unlike closed models such as GPT and Gemini."),
        Question(id: "at1_q4", type: .multipleChoice, questionText: "What does 'GPT' stand for in OpenAI's models?", options: ["Generative Pre-trained Transformer", "General Purpose Technology", "Guided Prediction Tool", "Global Processing Terminal"], correctAnswer: "Generative Pre-trained Transformer", explanation: "GPT stands for Generative Pre-trained Transformer, describing its architecture (Transformer), training approach (pre-trained on large data), and capability (generative text output)."),
        Question(id: "at1_q5", type: .fillInBlank, questionText: "Mistral AI is an AI company headquartered in __________, known for efficient open-weight models.", options: ["Paris", "San Francisco", "London", "Berlin"], correctAnswer: "Paris", explanation: "Mistral AI is a French AI company based in Paris that has gained attention for releasing high-performing open-weight models that rival much larger competitors."),
        Question(id: "at1_q6", type: .scenarioJudgment, questionText: "Your team needs an AI model you can run on your own servers without sending data to a third party. Which approach makes the most sense?", options: ["Use an open-weight model like Llama or Mistral", "Sign up for the GPT API from OpenAI", "Wait for a fully open version of Gemini", "Build your own model from scratch"], correctAnswer: "Use an open-weight model like Llama or Mistral", explanation: "Open-weight models like Llama and Mistral can be downloaded and run locally on your own infrastructure, keeping your data private without relying on external API services.")
    ], order: 0, difficulty: .beginner)

    static let lesson2 = LessonData(id: "at_l2", title: "Image & Video AI", description: "AI tools for visual content creation", categoryId: "ai_tools", questions: [
        Question(id: "at2_q1", type: .multipleChoice, questionText: "Which AI image generator is known for its distinctive artistic style and community-driven development through Discord?", options: ["Midjourney", "DALL-E", "Stable Diffusion", "Flux"], correctAnswer: "Midjourney", explanation: "Midjourney became famous for its painterly, artistic image quality and its unique Discord-based interface where users generate images through chat commands."),
        Question(id: "at2_q2", type: .trueFalse, questionText: "Stable Diffusion is an open-source image generation model that anyone can run on their own computer.", options: ["True", "False"], correctAnswer: "True", explanation: "Stable Diffusion, originally created by Stability AI, was released as open source, allowing users to run it locally, modify it, and build applications on top of it without paying per image."),
        Question(id: "at2_q3", type: .matchPairs, questionText: "Match each AI visual tool with its primary capability:", matchPairs: [
            MatchPair(term: "DALL-E", definition: "OpenAI's text-to-image generator"),
            MatchPair(term: "Sora", definition: "OpenAI's text-to-video generator"),
            MatchPair(term: "Runway", definition: "Video editing and generation platform"),
            MatchPair(term: "Flux", definition: "Open-source image generation model")
        ], explanation: "The AI visual creation space includes both image generators like DALL-E and Flux, and video generators like Sora and Runway, each with different strengths and access models."),
        Question(id: "at2_q4", type: .fillInBlank, questionText: "Most modern image generation AI models use a technique called __________, which starts with noise and gradually refines it into a coherent image.", options: ["diffusion", "compression", "rendering", "filtering"], correctAnswer: "diffusion", explanation: "Diffusion models work by learning to reverse a noise-adding process — they start with random noise and progressively denoise it into a clean image guided by the text prompt."),
        Question(id: "at2_q5", type: .multipleChoice, questionText: "What is a 'prompt' in the context of AI image generation?", options: ["A text description of the image you want to create", "The file format of the output image", "The resolution setting for the generated image", "The computing power required to generate the image"], correctAnswer: "A text description of the image you want to create", explanation: "A prompt is the natural language text input that describes what you want the AI to generate. Skilled prompt writing, sometimes called prompt engineering, can dramatically affect output quality."),
        Question(id: "at2_q6", type: .scenarioJudgment, questionText: "A designer wants to create many variations of a logo concept quickly using AI, with full control over the model and no per-image costs. Which tool fits best?", options: ["Stable Diffusion running locally", "Midjourney via Discord", "DALL-E through ChatGPT", "Sora for video generation"], correctAnswer: "Stable Diffusion running locally", explanation: "Running Stable Diffusion locally gives full control, unlimited generations with no per-image cost, and the ability to fine-tune the model on specific styles — ideal for iterative design work.")
    ], order: 1, difficulty: .beginner)

    static let lesson3 = LessonData(id: "at_l3", title: "AI for Code", description: "How AI is transforming software development", categoryId: "ai_tools", questions: [
        Question(id: "at3_q1", type: .multipleChoice, questionText: "What is GitHub Copilot?", options: ["An AI coding assistant that suggests code in your editor", "A version control system for managing code", "A cloud platform for deploying applications", "A programming language created by GitHub"], correctAnswer: "An AI coding assistant that suggests code in your editor", explanation: "GitHub Copilot integrates into code editors like VS Code and suggests code completions, entire functions, and solutions as you type, acting as an AI pair programmer."),
        Question(id: "at3_q2", type: .trueFalse, questionText: "AI coding assistants can write perfect, bug-free code that never needs human review.", options: ["True", "False"], correctAnswer: "False", explanation: "AI coding tools frequently produce code with bugs, security issues, or logic errors. Human review remains essential — these tools augment developers but do not replace careful code review and testing."),
        Question(id: "at3_q3", type: .sortOrder, questionText: "Put these steps of AI-assisted coding in the correct order:", options: ["Review and test the generated code", "Describe what you want the code to do", "AI generates a code suggestion", "Integrate the working code into your project"], correctAnswers: ["Describe what you want the code to do", "AI generates a code suggestion", "Review and test the generated code", "Integrate the working code into your project"], explanation: "Effective AI-assisted coding follows a cycle: describe your intent, let the AI generate code, carefully review and test the output, then integrate it. Skipping the review step is a common and costly mistake."),
        Question(id: "at3_q4", type: .matchPairs, questionText: "Match each AI coding tool with its distinguishing feature:", matchPairs: [
            MatchPair(term: "GitHub Copilot", definition: "Inline code suggestions in editors"),
            MatchPair(term: "Cursor", definition: "AI-native code editor"),
            MatchPair(term: "Claude Code", definition: "Terminal-based agentic coding"),
            MatchPair(term: "Replit", definition: "Browser-based coding with AI")
        ], explanation: "AI coding tools range from editor plugins like Copilot, to AI-first editors like Cursor, terminal agents like Claude Code, and cloud environments like Replit — each suited to different workflows."),
        Question(id: "at3_q5", type: .fillInBlank, questionText: "The practice of a human developer working alongside an AI assistant to write code is often called AI __________ programming.", options: ["pair", "solo", "parallel", "batch"], correctAnswer: "pair", explanation: "AI pair programming borrows the concept from traditional pair programming where two developers work together, but replaces one human with an AI that suggests, reviews, and explains code."),
        Question(id: "at3_q6", type: .scenarioJudgment, questionText: "A junior developer uses an AI coding tool that generates a database query. The code looks correct but they are not sure about security implications. What should they do?", options: ["Have a senior developer review the code before deploying", "Deploy it since AI-generated code is usually secure", "Rewrite the entire query manually from scratch", "Ask the AI if the code is secure and trust its answer"], correctAnswer: "Have a senior developer review the code before deploying", explanation: "AI-generated code can contain security vulnerabilities like SQL injection. Having experienced developers review AI-generated code, especially for security-sensitive operations, is a critical best practice.")
    ], order: 2, difficulty: .intermediate)

    static let lesson4 = LessonData(id: "at_l4", title: "Open Source vs Closed", description: "Understanding the open-closed spectrum in AI", categoryId: "ai_tools", questions: [
        Question(id: "at4_q1", type: .multipleChoice, questionText: "What is Hugging Face best known for in the AI community?", options: ["A platform for sharing and discovering AI models", "A proprietary large language model", "A cloud computing service for training AI", "A social media platform for AI researchers"], correctAnswer: "A platform for sharing and discovering AI models", explanation: "Hugging Face is the leading open platform where researchers and developers share AI models, datasets, and applications. It hosts thousands of models and has become the GitHub of the AI world."),
        Question(id: "at4_q2", type: .trueFalse, questionText: "The term 'open-weight' means the same thing as 'open-source' when it comes to AI models.", options: ["True", "False"], correctAnswer: "False", explanation: "Open-weight means the model weights are publicly available for download and use, but the training data and full training code may not be shared. True open-source would include all components needed to reproduce the model from scratch."),
        Question(id: "at4_q3", type: .matchPairs, questionText: "Match each license type with its key characteristic:", matchPairs: [
            MatchPair(term: "Apache 2.0", definition: "Very permissive, allows commercial use"),
            MatchPair(term: "Llama License", definition: "Free but with usage restrictions"),
            MatchPair(term: "Proprietary", definition: "No access to model weights"),
            MatchPair(term: "GPL", definition: "Requires sharing modifications")
        ], explanation: "AI model licensing varies widely. Apache 2.0 is the most permissive, Llama's license allows broad use but with conditions, proprietary models like GPT offer API-only access, and GPL requires derivative works to also be open."),
        Question(id: "at4_q4", type: .multipleChoice, questionText: "What is Ollama?", options: ["A tool for running AI models locally on your computer", "A cloud-based AI training platform", "A new large language model from Google", "A dataset for fine-tuning language models"], correctAnswer: "A tool for running AI models locally on your computer", explanation: "Ollama is a popular tool that makes it easy to download and run open-weight language models like Llama and Mistral on your local machine, without needing cloud services or API keys."),
        Question(id: "at4_q5", type: .fillInBlank, questionText: "Running an AI model on your own hardware instead of using a cloud API is called running it __________.", options: ["locally", "remotely", "virtually", "externally"], correctAnswer: "locally", explanation: "Running models locally means the computation happens on your own machine. This provides privacy, avoids per-request costs, and allows offline use, but requires sufficient hardware — especially GPU memory."),
        Question(id: "at4_q6", type: .scenarioJudgment, questionText: "A healthcare startup wants to use AI to process sensitive patient data. They are concerned about privacy regulations. What approach should they consider first?", options: ["Running an open-weight model on their own private servers", "Sending data to a major cloud AI API with encryption", "Waiting until AI regulations are finalized before starting", "Using a free consumer chatbot for initial prototyping"], correctAnswer: "Running an open-weight model on their own private servers", explanation: "For sensitive healthcare data, running an open-weight model on private infrastructure keeps patient data within the organization's control, which is critical for HIPAA compliance and data sovereignty.")
    ], order: 3, difficulty: .intermediate)

    static let lesson5 = LessonData(id: "at_l5", title: "APIs & Integration", description: "How developers build with AI behind the scenes", categoryId: "ai_tools", questions: [
        Question(id: "at5_q1", type: .multipleChoice, questionText: "What is an API in the context of AI services?", options: ["A way for applications to send requests to an AI model and receive responses", "The graphical interface used to chat with an AI model", "A type of neural network architecture", "A programming language for building AI models"], correctAnswer: "A way for applications to send requests to an AI model and receive responses", explanation: "An API (Application Programming Interface) lets developers programmatically send prompts to an AI model and receive generated responses, enabling AI to be embedded into apps, websites, and services."),
        Question(id: "at5_q2", type: .trueFalse, questionText: "When you use an app that has AI features, the app is often calling an AI API behind the scenes rather than running its own model.", options: ["True", "False"], correctAnswer: "True", explanation: "Most apps with AI features use APIs from providers like Anthropic, OpenAI, or Google to access powerful models. Running large AI models directly is expensive, so API access is far more practical for most developers."),
        Question(id: "at5_q3", type: .sortOrder, questionText: "Put these steps of making an AI API call in the correct order:", options: ["Receive the AI model's response", "Authenticate with your API key", "Send a request with your prompt", "Parse and display the response in your app"], correctAnswers: ["Authenticate with your API key", "Send a request with your prompt", "Receive the AI model's response", "Parse and display the response in your app"], explanation: "A typical AI API call flow starts with authentication, sends the user's prompt to the model, receives the response, and then the developer's code processes and displays that response to the end user."),
        Question(id: "at5_q4", type: .fillInBlank, questionText: "An API __________ is a secret code that identifies your application and authorizes it to use an AI service.", options: ["key", "bridge", "socket", "chain"], correctAnswer: "key", explanation: "API keys are unique identifiers that authenticate your requests. They should be kept secret — exposing an API key publicly can lead to unauthorized usage and unexpected charges on your account."),
        Question(id: "at5_q5", type: .multipleChoice, questionText: "What is a 'rate limit' on an AI API?", options: ["A restriction on how many requests you can make in a given time period", "The speed at which the AI model generates text", "The maximum length of a single prompt you can send", "The monthly cost cap for using the service"], correctAnswer: "A restriction on how many requests you can make in a given time period", explanation: "Rate limits prevent any single user from overwhelming the service. For example, an API might allow 100 requests per minute. Exceeding the limit results in temporary request rejections."),
        Question(id: "at5_q6", type: .scenarioJudgment, questionText: "A developer accidentally commits their AI API key to a public GitHub repository. What should they do immediately?", options: ["Revoke the key and generate a new one right away", "Delete the commit from the repository history", "Change the repository to private", "Monitor usage to see if anyone exploits it first"], correctAnswer: "Revoke the key and generate a new one right away", explanation: "Exposed API keys can be exploited within minutes by automated scanners. The first priority is always to revoke the compromised key immediately, then generate a new one and store it securely using environment variables or a secrets manager.")
    ], order: 4, difficulty: .advanced)

    static let lesson6 = LessonData(id: "at_l6", title: "AI Agents & Automation", description: "The next frontier of AI interaction", categoryId: "ai_tools", questions: [
        Question(id: "at6_q1", type: .multipleChoice, questionText: "What is an AI agent?", options: ["An AI system that can plan and execute multi-step tasks autonomously", "A human employee who specializes in AI technology", "A simple chatbot that answers frequently asked questions", "A hardware device that runs AI models locally"], correctAnswer: "An AI system that can plan and execute multi-step tasks autonomously", explanation: "AI agents go beyond simple question-answering by breaking complex tasks into steps, using tools, and making decisions along the way — acting more like an autonomous assistant than a one-shot responder."),
        Question(id: "at6_q2", type: .trueFalse, questionText: "Function calling allows an AI model to request the execution of specific actions, like searching the web or querying a database, during a conversation.", options: ["True", "False"], correctAnswer: "True", explanation: "Function calling (also called tool use) lets AI models invoke predefined functions during generation. For example, Claude can call a weather API, run code, or search documents when it determines those tools would help answer a question."),
        Question(id: "at6_q3", type: .matchPairs, questionText: "Match each agentic AI concept with its description:", matchPairs: [
            MatchPair(term: "Tool Use", definition: "AI calling external functions"),
            MatchPair(term: "MCP", definition: "Standard protocol for connecting AI to tools"),
            MatchPair(term: "Multi-step Reasoning", definition: "Breaking a task into sequential steps"),
            MatchPair(term: "Agentic Workflow", definition: "AI autonomously completing complex tasks")
        ], explanation: "Agentic AI combines tool use, multi-step reasoning, and protocols like MCP (Model Context Protocol) to create workflows where AI systems can autonomously tackle complex, real-world tasks."),
        Question(id: "at6_q4", type: .fillInBlank, questionText: "MCP stands for Model __________ Protocol, a standard for connecting AI models to external tools and data sources.", options: ["Context", "Computing", "Communication", "Control"], correctAnswer: "Context", explanation: "The Model Context Protocol (MCP) is an open standard developed by Anthropic that provides a universal way to connect AI models to external data sources and tools, replacing fragmented custom integrations."),
        Question(id: "at6_q5", type: .multipleChoice, questionText: "What is a key difference between a regular chatbot and an AI agent?", options: ["An agent can use tools and take actions across multiple steps", "An agent always has a physical robotic body", "An agent uses a different type of neural network", "An agent can only respond to voice commands"], correctAnswer: "An agent can use tools and take actions across multiple steps", explanation: "While a chatbot typically handles single-turn conversations, an AI agent can plan multi-step strategies, use external tools like file systems and APIs, observe results, and adjust its approach — operating more like an autonomous worker."),
        Question(id: "at6_q6", type: .scenarioJudgment, questionText: "A company wants to build an AI agent that can autonomously process customer refunds, including accessing payment systems and modifying account data. What is the most important consideration?", options: ["Implementing human oversight for high-stakes actions", "Making the agent respond as quickly as possible", "Training the agent on as much customer data as possible", "Ensuring the agent can handle multiple refunds simultaneously"], correctAnswer: "Implementing human oversight for high-stakes actions", explanation: "When AI agents can take real-world actions involving money or sensitive data, human-in-the-loop oversight is critical. Best practice is to have the agent propose actions and require human approval for high-stakes decisions like financial transactions.")
    ], order: 5, difficulty: .advanced)
}
